/**
 * 多段路径组装工具
 * @param proxyList
 */
export const pathJoin = (...proxyList: any[]) =>
    `/${proxyList
        // v 允许（排除值为'/'的情况外）布尔转换后的为真值的情况，以及 v 等于 0 本身的情况。
        .filter((v) => (!!v && v !== '/') || v === 0)
        .map((v) => {
            let i = v?.toString();
            if (v?.toString().startsWith('/')) {
                i = i?.slice(1);
            }
            if (v?.toString().endsWith('/')) {
                i = i?.slice(0, -1);
            }
            return i;
        })
        .join('/')}`;